import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';
import { CentsPipe } from '../../shared/cents.pipe';
import { Lease } from '../../core/models';

@Component({
  selector: 'app-my-lease',
  standalone: true,
  imports: [CommonModule, RouterLink, CentsPipe],
  templateUrl: './my-lease.component.html',
  styleUrl: './my-lease.component.css',
})
export class MyLeaseComponent {
  readonly loading = signal(false);
  readonly error = signal('');

  /** Tenant's lease — Alex Rivera, unit 101. */
  readonly lease = signal<Lease | null>({
    id: 'l1',
    unitId: 'u1',
    tenantId: 't1',
    startsOn: '2025-01-01',
    endsOn: '2026-12-31',
    rentCents: 120000,
    dueDay: 1,
    status: 'current',
  });

  /** Current outstanding balance in integer cents. */
  readonly balance = signal<number>(120000);

  // ---- Pay flow state ----
  readonly confirming = signal(false);
  readonly paying = signal(false);
  readonly paid = signal(false);
  readonly lastReceiptId = signal<string | null>(null);
  readonly lastReceiptNumber = signal<string | null>(null);

  constructor(private router: Router) {}

  startPay(): void {
    if (this.balance() === 0) return;
    this.confirming.set(true);
  }

  cancelPay(): void {
    this.confirming.set(false);
  }

  confirmPay(): void {
    this.paying.set(true);
    // Simulate a payment round-trip.
    setTimeout(() => {
      this.balance.set(0);
      this.lastReceiptNumber.set('R-00003');
      this.lastReceiptId.set('r3');
      this.paying.set(false);
      this.confirming.set(false);
      this.paid.set(true);
    }, 600);
  }

  viewReceipt(): void {
    const id = this.lastReceiptId();
    if (id) this.router.navigate(['/receipt', id]);
  }
}
